const fs = require('fs');
const path='/tmp/n8n_kb_estado.json';
let db={kb:{}, estado:{}};
if (fs.existsSync(path)) { try { db = JSON.parse(fs.readFileSync(path,'utf8')); } catch(e){} }
const protocol=$('Set - Normalizar Payload').item.json.protocol || '';
const numero=$('Set - Normalizar Payload').item.json.customer_id || '';
const customer_name=$('Set - Normalizar Payload').item.json.customer_name || '';
const correlation_key=`${protocol}::${numero}`;
const src=String($('Set - Normalizar Payload').item.json.message_text || '').trim();
const low=src.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const usefulShort = new Set(['oi','ola','olá','bom dia','boa tarde','boa noite','sim','ok','pode','1','2']);
const quality_ok = src.length >= 2 || usefulShort.has(low);

const state=db.estado[correlation_key] || {attempt_count:0,resolved:false,ticket_created:false,ticket_id:'',schedule_started:false, contexto:{}};
const ctx=state.contexto || {};
const contexto = {
  protocolo: ctx.protocolo || protocol,
  numero: ctx.numero || numero,
  nome: ctx.nome || customer_name || '',
  empresa: ctx.empresa || '',
  identificado: !!ctx.identificado,
  triagem_concluida: !!ctx.triagem_concluida,
  tentativas: Number(ctx.tentativas || 0),
  ticket_aberto: !!ctx.ticket_aberto,
  agendamento_enviado: !!ctx.agendamento_enviado,
  encerrado: !!ctx.encerrado,
  updated_at: ctx.updated_at || '',
  last_status: ctx.last_status || '',
  last_intent: ctx.last_intent || '',
  last_event_type: ctx.last_event_type || '',
  ultima_solicitacao_tipo: ctx.ultima_solicitacao_tipo || ''
};

const intent=$('Code - Gerar Chave KB').item.json.knowledge_key || 'fallback_generico';
const stage='fallback_openclaw';
const kb_key=`${intent}::${stage}`;
const hit=db.kb[kb_key] || null;
return [{json:{...$json, db_path:path, correlation_key, quality_ok, intent, stage, kb_key, answer_found:!!hit, kb_record:hit, state, contexto, already_resolved:false}}];

const fs = require('fs');
const path='/tmp/n8n_kb_estado.json';
let db={kb:{}, estado:{}};
if (fs.existsSync(path)) { try { db = JSON.parse(fs.readFileSync(path,'utf8')); } catch(e){} }
const key = $json.correlation_key || `${$('Set - Normalizar Payload').item.json.protocol}::${$('Set - Normalizar Payload').item.json.customer_id}`;
const prev = db.estado[key] || {attempt_count:0,resolved:false,ticket_created:false,ticket_id:'',schedule_started:false, contexto:{}};
const ctx = $json.contexto_atualizado || prev.contexto || {};
const incomingTicket = $('Set - Normalizar Payload').item.json.ticket_id || '';
const route_branch = ($json.status === 'ENCERRADO') ? 'encerrado' : ($json.handoff_humano ? 'handoff' : ($json.agendar ? 'agendar' : 'default'));

db.estado[key] = {
  ...prev,
  protocolo: $('Set - Normalizar Payload').item.json.protocol,
  numero: $('Set - Normalizar Payload').item.json.customer_id,
  contexto: ctx,
  ticket_id: prev.ticket_id || incomingTicket || '',
  ticket_created: !!(prev.ticket_created || $json.abrir_ticket),
  updated_at: new Date().toISOString()
};

if (ctx.encerrado) {
  db.estado[key].resolved = true;
}

fs.writeFileSync(path, JSON.stringify(db,null,2));
return [{json:{...$json, state: db.estado[key], route_branch}}];
